const body = $input.first().json.body || $input.first().json;
return [{ json: {
  session_id: body.session_id || ('email_' + Date.now()),
  subject: body.subject || body.email_subject || '',
  original_email: body.original_email || body.email || body.email_thread || body.thread || body.message || '',
  context: body.context || body.notes || '',
  tone: body.tone || 'professional',
  sender_name: body.sender_name || body.from_name || '',
  sender_role: body.sender_role || body.from_role || '',
  your_name: body.your_name || 'Shawn Seffernick',
  your_role: body.your_role || 'President, Envision Innovative Solutions'
}}];

const raw = $input.first().json;
const input = $('Parse Email Input').first().json;
let parsed = {};
try {
  const text = raw.content?.[0]?.text || '{}';
  const clean = text.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  parsed = { subject: 'RE: ' + input.subject, response: 'Unable to parse response', key_points: [], tone_notes: '' };
}
return [{ json: { ...input, ...parsed, processed_at: new Date().toISOString() } }];

if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];
